const t=k=>T[currentLang]?.[k]||T.fr[k]||T.en[k]||'...';const $=s=>document.querySelector(s),$$=s=>Array.from(document.querySelectorAll(s));const safe=v=>Trainw.safeVal(v,'—');const dayNames=['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
