function weekdayMatch(label){const low=String(label||'').toLowerCase();const map={sunday:['sunday','dimanche','الأحد'],monday:['monday','lundi','الاثنين'],tuesday:['tuesday','mardi','الثلاثاء'],wednesday:['wednesday','mercredi','الأربعاء'],thursday:['thursday','jeudi','الخميس'],friday:['friday','vendredi','الجمعة'],saturday:['saturday','samedi','السبت']};const key=dayNames[new Date().getDay()].toLowerCase();return(map[key]||[]).some(x=>low.includes(x))}
function streak(rows){const days=Array.from(new Set((rows||[]).map(x=>String(x.checked_in_at||'').slice(0,10)))).sort().reverse();let n=0,c=new Date();c.setHours(0,0,0,0);for(const day of days){const cur=Trainw.dateOnly(c),prev=Trainw.dateOnly(Trainw.addDays(c,-1));if(day===cur||(n>0&&day===prev)){n+=1;c=Trainw.addDays(c,-1);continue}if(n===0&&day===prev){n+=1;c=Trainw.addDays(c,-2);continue}break}return n}
function sessionAt(s){return new Date(`${s.session_date}T${s.start_time||'00:00:00'}`).getTime()}
function isFutureSession(s){return sessionAt(s)>=Date.now()}
function bookingMeta(status){const map={pending:{label:t('bookingPending'),cls:'pending'},confirmed:{label:t('bookingConfirmed'),cls:'confirmed'},completed:{label:t('bookingCompleted'),cls:'completed'},cancelled:{label:t('bookingCancelled'),cls:'cancelled'}};return map[status]||map.pending}
function ensureBookingDefaults(){const tomorrow=Trainw.dateOnly(Trainw.addDays(new Date(),1));if(!selectedBookingDate||selectedBookingDate<Trainw.dateOnly(new Date()))selectedBookingDate=tomorrow;if(availableCoaches.length&&!availableCoaches.some(c=>c.user_id===selectedBookingCoachId))selectedBookingCoachId=availableCoaches[0].user_id;if(!availableCoaches.length){selectedBookingCoachId='';selectedBookingSlot=''}}
async function loadBookingSlots(silent){ensureBookingDefaults();if(!selectedBookingCoachId||!selectedBookingDate){bookingSlots=[];selectedBookingSlot='';return}const r=await Trainw.api.run(sb.rpc('get_bookable_slots',{p_coach_id:selectedBookingCoachId,p_session_date:selectedBookingDate}),{context:'load bookable slots',fallback:[],silent:!!silent,toastOnError:!silent});bookingSlots=Array.isArray(r.data)?r.data:[];if(!bookingSlots.some(slot=>slot.slot_time===selectedBookingSlot))selectedBookingSlot=''}
async function loadData(){const assignRes=await Trainw.api.run(sb.from('coach_client_assignments').select('coach_id').eq('client_id',currentUserId).eq('gym_id',currentGymId).eq('is_active',true).limit(1),{context:'load coach assignment',fallback:[]});const assignedCoachId=assignRes.data?.[0]?.coach_id||null;const [profileRes,ownerRes,sessionsRes,planRes,weightRes,goalRes,checkRes,msgRes,coachesRes,reviewsRes]=await Promise.all([Trainw.api.run(sb.from('client_profiles').select('*').eq('user_id',currentUserId).maybeSingle(),{context:'load client profile',fallback:null}),Trainw.api.run(sb.from('users').select('id,name,role').eq('gym_id',currentGymId).in('role',['gym_owner','gym','admin']).limit(1),{context:'load gym owner',fallback:[]}),Trainw.api.run(sb.from('sessions').select('id,gym_id,session_date,start_time,end_time,duration_minutes,type,status,coach_id,session_name,notes,cancellation_reason,users!sessions_coach_id_fkey(name)').eq('client_id',currentUserId).order('session_date',{ascending:true}).order('start_time',{ascending:true}),{context:'load personal sessions',fallback:[]}),Trainw.api.run(sb.from('workout_plans').select('*').eq('client_id',currentUserId).eq('gym_id',currentGymId).order('updated_at',{ascending:false}).limit(1),{context:'load active plan',fallback:[]}),Trainw.api.run(sb.from('weight_logs').select('*').eq('client_id',currentUserId).eq('gym_id',currentGymId).order('logged_at',{ascending:false}),{context:'load weight logs',fallback:[]}),Trainw.api.run(sb.from('client_goals').select('*').eq('client_id',currentUserId).eq('gym_id',currentGymId).order('created_at',{ascending:false}).limit(1),{context:'load goals',fallback:[]}),Trainw.api.run(sb.from('check_ins').select('*').eq('client_id',currentUserId).eq('gym_id',currentGymId).order('checked_in_at',{ascending:false}).limit(60),{context:'load checkins',fallback:[]}),Trainw.api.run(sb.from('messages').select('*').or(`sender_id.eq.${currentUserId},receiver_id.eq.${currentUserId}`).order('created_at',{ascending:false}).limit(200),{context:'load messages',fallback:[]}),Trainw.api.run(sb.from('coach_profiles').select('id,user_id,gym_id,specialty,specialties,price_per_session,hourly_rate,rating,total_reviews,users:users!coach_profiles_user_id_fkey(id,name,phone,gym_id)').eq('gym_id',currentGymId).eq('approval_status','approved').eq('is_active',true).order('rating',{ascending:false}),{context:'load approved coaches',fallback:[]}),Trainw.api.run(sb.from('reviews').select('id,session_id,coach_id,client_id,rating,comment,created_at').eq('client_id',currentUserId),{context:'load reviews',fallback:[]})]);clientProfile=profileRes.data||null;ownerInfo=ownerRes.data?.[0]||null;mySessions=Array.isArray(sessionsRes.data)?sessionsRes.data:[];activePlan=planRes.data?.[0]||null;weightLogs=Array.isArray(weightRes.data)?weightRes.data:[];currentGoal=goalRes.data?.[0]||null;checkins=Array.isArray(checkRes.data)?checkRes.data:[];availableCoaches=Array.isArray(coachesRes.data)?coachesRes.data:[];reviewsBySession=new Map((reviewsRes.data||[]).map(r=>[r.session_id,r]));const primaryCoachId=assignedCoachId||mySessions.find(s=>s.coach_id)?.coach_id||null;if(primaryCoachId){const [coachUser,coachProfile]=await Promise.all([Trainw.api.run(sb.from('users').select('id,name,phone').eq('id',primaryCoachId).maybeSingle(),{context:'load primary coach',fallback:null}),Trainw.api.run(sb.from('coach_profiles').select('specialty').eq('user_id',primaryCoachId).maybeSingle(),{context:'load primary coach profile',fallback:null})]);coachInfo={id:primaryCoachId,name:coachUser.data?.name||'Coach',phone:coachUser.data?.phone||'',specialty:coachProfile.data?.specialty||''}}else coachInfo=null;if(activePlan){const ex=await Trainw.api.run(sb.from('workout_exercises').select('*').eq('plan_id',activePlan.id).order('order_index',{ascending:true}),{context:'load exercises',fallback:[]});planExercises=ex.data||[]}else planExercises=[];workoutLogs=(await Trainw.api.run(sb.from('workout_logs').select('*').eq('client_id',currentUserId).eq('gym_id',currentGymId).order('completed_at',{ascending:false}).limit(10),{context:'load workout logs',fallback:[]})).data||[];logSetsMap=new Map();if(workoutLogs.length){const setRes=await Trainw.api.run(sb.from('workout_log_sets').select('*').in('log_id',workoutLogs.map(x=>x.id)),{context:'load workout log sets',fallback:[]});(setRes.data||[]).forEach(set=>{const arr=logSetsMap.get(set.log_id)||[];arr.push(set);logSetsMap.set(set.log_id,arr)})}const participants=Array.from(new Set([primaryCoachId,ownerInfo?.id].filter(Boolean)));threads=participants.map(id=>{const info=id===coachInfo?.id?coachInfo:ownerInfo;const messages=(msgRes.data||[]).filter(m=>m.sender_id===id||m.receiver_id===id).sort((a,b)=>new Date(a.created_at)-new Date(b.created_at));return{id,name:info?.name||'Contact',role:id===coachInfo?.id?t('coachLabel'):t('ownerLabel'),messages}}).filter(x=>x.id);ensureBookingDefaults();await loadBookingSlots(true);renderAll()}
function applyTranslations(){document.documentElement.lang=currentLang;Trainw.applyDocumentLanguage(currentLang,'.app-container');$$('[data-i18n]').forEach(el=>el.textContent=t(el.getAttribute('data-i18n')));$$('[data-i18n-ph]').forEach(el=>el.setAttribute('placeholder',t(el.getAttribute('data-i18n-ph'))));$$('.lang-btn').forEach(b=>b.classList.toggle('active',b.dataset.lang===currentLang))}
function showPage(page){$$('.page').forEach(p=>p.classList.add('hidden'));$('#'+page+'-page')?.classList.remove('hidden');$$('.nav-item').forEach(n=>n.classList.toggle('active',n.dataset.page===page))}
function coachMeta(coach){return t('bookingCoachMeta').replace('{price}',String(Number(coach.price_per_session??coach.hourly_rate??0)||0)).replace('{reviews}',String(coach.total_reviews||0))}
function renderDashboard(){const month=new Date().getMonth(),weekStart=new Date();weekStart.setDate(weekStart.getDate()-weekStart.getDay());weekStart.setHours(0,0,0,0);Trainw.ui.setText('stat-checkins',String(checkins.filter(c=>new Date(c.checked_in_at).getMonth()===month).length));Trainw.ui.setText('stat-sessions',String(mySessions.filter(s=>sessionAt(s)>=weekStart.getTime()&&s.status!=='cancelled').length));Trainw.ui.setText('stat-streak',String(streak(checkins)));const days=clientProfile?.membership_end_date?Math.ceil((new Date(clientProfile.membership_end_date)-new Date())/86400000):null;Trainw.ui.setText('stat-expiry',days===null?'-':days<0?t('membershipExpired'):String(days));Trainw.ui.setText('stat-expiry-sub',days===null?'-':days<0?t('membershipExpired'):days<7?t('membershipSoon').replace('{days}',String(days)):t('membershipActive').replace('{days}',String(days)));const upcoming=[...mySessions].filter(s=>s.status!=='cancelled'&&isFutureSession(s)).sort((a,b)=>sessionAt(a)-sessionAt(b)).slice(0,8);$('#dashboard-upcoming-list').innerHTML=upcoming.length?upcoming.map(s=>{const st=bookingMeta(s.status),canCancel=['pending','confirmed'].includes(s.status);return `<div class="session-list-item"><div><div class="activity-title">${Trainw.escapeHTML(s.session_name||'Coach session')}</div><div class="activity-meta">${Trainw.escapeHTML(fmtDate(s.session_date))} · ${Trainw.escapeHTML(String(s.start_time||'').slice(0,5))} · ${Trainw.escapeHTML(s.users?.name||'Coach')}</div><div class="activity-meta">${Trainw.escapeHTML(t('statusLabel'))}: ${Trainw.escapeHTML(st.label)}</div></div><div class="booking-session-actions"><span class="booking-status-pill ${st.cls}">${Trainw.escapeHTML(st.label)}</span>${canCancel?`<button class="btn-secondary" type="button" data-cancel-session="${s.id}">${Trainw.escapeHTML(t('cancelBooking'))}</button>`:''}</div></div>`}).join(''):`<p class="empty-state">${t('noSessions')}</p>`;const todayExercises=planExercises.filter(x=>weekdayMatch(x.day_label));$('#dashboard-today-program').innerHTML=todayExercises.length?todayExercises.map(x=>`<div class="today-plan-item"><div><strong>${Trainw.escapeHTML(x.exercise_name)}</strong><div class="activity-meta">${Trainw.escapeHTML(String(safe(x.sets)))} x ${Trainw.escapeHTML(String(safe(x.reps)))} · ${Trainw.escapeHTML(String(safe(x.rest_seconds,0)))}s</div></div></div>`).join(''):`<p class="empty-state">${t('noWorkoutToday')}</p>`;$('#btn-start-workout').disabled=!todayExercises.length;renderBookingComposer();renderPastSessions()}
function renderBookingComposer(){const search=String($('#booking-coach-search')?.value||'').trim().toLowerCase(),list=availableCoaches.filter(c=>!search||[c.users?.name,c.specialty,(c.specialties||[]).join(' ')].map(v=>String(v||'').toLowerCase()).some(v=>v.includes(search)));const selected=availableCoaches.find(c=>c.user_id===selectedBookingCoachId)||null;const dateInput=$('#booking-date-input');if(dateInput){dateInput.min=Trainw.dateOnly(new Date());dateInput.value=selectedBookingDate}$('#booking-coach-list').innerHTML=list.length?list.map(c=>`<button class="coach-pick-card ${c.user_id===selectedBookingCoachId?'selected':''}" type="button" data-book-coach="${c.user_id}"><div class="coach-pick-name">${Trainw.escapeHTML(c.users?.name||'Coach')}</div><div class="coach-pick-meta">${Trainw.escapeHTML(c.specialty||(c.specialties||[]).join(', ')||'Coach')}</div><div class="coach-pick-price">${Trainw.escapeHTML(coachMeta(c))}</div></button>`).join(''):`<p class="empty-state">${t('noCoachesAvailable')}</p>`;$('#booking-selected-coach').innerHTML=selected?`<div class="booking-selection-title">${Trainw.escapeHTML(selected.users?.name||'Coach')}</div><div class="booking-selection-sub">${Trainw.escapeHTML(coachMeta(selected))}</div><div class="booking-selection-sub">${Trainw.escapeHTML(selected.specialty||(selected.specialties||[]).join(', ')||'')}</div>`:`<p class="empty-state">${t('chooseCoachFirst')}</p>`;const slotList=$('#booking-slot-list');if(!selectedBookingCoachId)slotList.innerHTML=`<p class="empty-state">${t('chooseCoachFirst')}</p>`;else if(!selectedBookingDate)slotList.innerHTML=`<p class="empty-state">${t('chooseDatePrompt')}</p>`;else if(!bookingSlots.length)slotList.innerHTML=`<p class="empty-state">${t('bookingSlotsEmpty')}</p>`;else slotList.innerHTML=bookingSlots.map(slot=>`<button class="slot ${slot.slot_time===selectedBookingSlot?'selected':''}" type="button" data-slot-time="${slot.slot_time}"><span class="slot-time">${Trainw.escapeHTML(slot.slot_time)}</span><span class="slot-copy">${Trainw.escapeHTML(t('slotUntil').replace('{time}',slot.slot_end_time))}</span></button>`).join('')}
function renderPastSessions(){const past=[...mySessions].filter(s=>s.status==='completed'||s.status==='cancelled'||!isFutureSession(s)).sort((a,b)=>sessionAt(b)-sessionAt(a));$('#client-past-sessions-list').innerHTML=past.length?past.map(s=>{const st=bookingMeta(s.status),review=reviewsBySession.get(s.id),draft=reviewDrafts.get(s.id)||{rating:0,comment:''};const reviewBox=review?`<div class="review-box"><div class="goal-item-label">${Trainw.escapeHTML(t('reviewExisting'))}</div><div class="review-copy">${Trainw.escapeHTML(t('reviewRatingLabel'))}: ${Trainw.escapeHTML(String(review.rating))}/5</div><div class="review-copy">${Trainw.escapeHTML(review.comment||'')}</div></div>`:s.status==='completed'?`<div class="review-box"><div class="goal-item-label">${Trainw.escapeHTML(t('reviewTitle'))}</div><div class="review-rating">${[1,2,3,4,5].map(n=>`<button class="review-star ${draft.rating>=n?'active':''}" type="button" data-review-rating="${n}" data-review-session="${s.id}">${n}</button>`).join('')}</div><textarea class="form-input" rows="3" data-review-comment="${s.id}" placeholder="${Trainw.escapeHTML(t('reviewPlaceholder'))}">${Trainw.escapeHTML(draft.comment||'')}</textarea><div class="booking-session-actions"><button class="btn-primary" type="button" data-review-submit="${s.id}">${Trainw.escapeHTML(t('reviewSubmit'))}</button></div></div>`:'';return `<div class="booking-history-card booking-session-card"><div class="booking-session-top"><div><div class="booking-session-title">${Trainw.escapeHTML(s.session_name||'Coach session')}</div><div class="booking-session-meta">${Trainw.escapeHTML(fmtDate(s.session_date))} · ${Trainw.escapeHTML(String(s.start_time||'').slice(0,5))} · ${Trainw.escapeHTML(s.users?.name||'Coach')}</div>${s.cancellation_reason?`<div class="booking-session-meta">${Trainw.escapeHTML(s.cancellation_reason)}</div>`:''}</div><span class="booking-status-pill ${st.cls}">${Trainw.escapeHTML(st.label)}</span></div>${reviewBox}</div>`}).join(''):`<p class="empty-state">${t('noBookingHistory')}</p>`}
function planByDay(){const map={};planExercises.forEach(x=>{const k=x.day_label||'Jour';(map[k]=map[k]||[]).push(x)});return Object.entries(map)}
function renderProgram(){const days=planByDay();$('#program-accordion').innerHTML=days.length?days.map(([day,items],i)=>`<article class="program-day-card ${i===0?'open':''}"><div class="program-day-head"><div class="program-day-title">${Trainw.escapeHTML(day)}</div><button class="btn-secondary" data-toggle-day="${i}">+</button></div><div class="program-day-body">${items.map(x=>`<div class="program-ex-row"><strong>${Trainw.escapeHTML(x.exercise_name)}</strong><span>${Trainw.escapeHTML(String(safe(x.sets)))} x ${Trainw.escapeHTML(String(safe(x.reps)))} · ${Trainw.escapeHTML(String(safe(x.rest_seconds,0)))}s</span><span>${Trainw.escapeHTML(safe(x.notes,''))}</span></div>`).join('')}</div></article>`).join(''):`<p class="empty-state">${t('noPlan')}</p>`;$('#program-log-list').innerHTML=workoutLogs.length?workoutLogs.map(log=>`<div class="session-list-item"><div><div class="activity-title">${Trainw.escapeHTML(fmtDateTime(log.completed_at))}</div><div class="activity-meta">${Trainw.escapeHTML(String(safe(log.duration_minutes)))} min · RPE ${Trainw.escapeHTML(String(safe(log.perceived_effort)))} · ${Trainw.escapeHTML(safe(log.notes,''))}</div><div class="activity-meta">${Trainw.escapeHTML((logSetsMap.get(log.id)||[]).map(s=>`${s.exercise_name} ${s.reps_done||'-'}x${s.weight_kg||'-'}`).join(' · '))}</div></div><div>${Trainw.renderEffortBar(log.perceived_effort||0)}</div></div>`).join(''):`<p class="empty-state">${t('noData')}</p>`}
function renderWeight(){const ctx=$('#weight-progress-chart');if(ctx&&window.Chart){weightChart?.destroy();const rev=[...weightLogs].reverse();const datasets=[{label:t('weightKg'),data:rev.map(x=>+x.weight_kg||null),borderColor:'#C8F135',backgroundColor:'rgba(200,241,53,.12)',fill:true,tension:.3,borderWidth:3}];if($('#toggle-bodyfat').checked)datasets.push({label:t('bodyFatPct'),data:rev.map(x=>+x.body_fat_pct||null),borderColor:'#3d8eff',borderDash:[8,6],tension:.3,borderWidth:2});weightChart=new Chart(ctx,{type:'line',data:{labels:rev.map(x=>fmtDate(x.logged_at)),datasets},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{labels:{color:'#efefef'}}},scales:{x:{ticks:{color:'#888'},grid:{color:'rgba(255,255,255,0.06)'}},y:{ticks:{color:'#888'},grid:{color:'rgba(255,255,255,0.06)'}}}}})}const start=weightLogs[weightLogs.length-1]?.weight_kg||null,current=weightLogs[0]?.weight_kg||null,target=currentGoal?.target_weight_kg||null;let pct=0;if(start&&current&&target&&start!==target)pct=Math.max(0,Math.min(100,Math.round(((start-current)/(start-target))*100)));$('#goal-progress-fill').style.width=pct+'%';$('#goal-progress-copy').textContent=target?`${pct}% · ${t('targetWeight')}: ${target} kg`:'-';$('#weight-date-input').value=Trainw.dateOnly(new Date());$('#weight-table-wrap').innerHTML=weightLogs.length?`<table><thead><tr><th>${t('dateLabel')}</th><th>${t('weightKg')}</th><th>${t('bodyFatPct')}</th><th>${t('notesLabel')}</th></tr></thead><tbody>${weightLogs.map(w=>`<tr><td>${Trainw.escapeHTML(fmtDate(w.logged_at))}</td><td>${Trainw.escapeHTML(String(safe(w.weight_kg)))}</td><td>${Trainw.escapeHTML(String(safe(w.body_fat_pct)))}</td><td>${Trainw.escapeHTML(safe(w.notes,''))}</td></tr>`).join('')}</tbody></table>`:`<p class="empty-state">${t('noData')}</p>`}
function renderGoals(){if(currentGoal){const days=currentGoal.target_date?Math.ceil((new Date(currentGoal.target_date)-new Date())/86400000):null;$('#goal-card-view').innerHTML=`<div class="goal-card"><div class="goal-grid"><div class="goal-item"><div class="goal-item-label">${t('goalType')}</div><div class="goal-item-value">${Trainw.escapeHTML(safe(currentGoal.goal_type))}</div></div><div class="goal-item"><div class="goal-item-label">${t('targetWeight')}</div><div class="goal-item-value">${Trainw.escapeHTML(String(safe(currentGoal.target_weight_kg)))}</div></div><div class="goal-item"><div class="goal-item-label">${t('targetDate')}</div><div class="goal-item-value">${Trainw.escapeHTML(fmtDate(currentGoal.target_date))}</div></div><div class="goal-item"><div class="goal-item-label">${t('goalDays')}</div><div class="goal-item-value">${Trainw.escapeHTML(days===null?'-':String(days))}</div></div></div><div style="margin-top:14px;color:var(--mt);">${Trainw.escapeHTML(safe(currentGoal.notes,''))}</div></div>`;$('#goal-type-input').value=currentGoal.goal_type||'general';$('#goal-target-weight').value=currentGoal.target_weight_kg||'';$('#goal-date-input').value=currentGoal.target_date||'';$('#goal-notes-input').value=currentGoal.notes||''}else $('#goal-card-view').innerHTML=`<p class="empty-state">${t('noGoal')}</p>`}
function renderCheckins(){const today=Trainw.dateOnly(new Date()),seen=new Set(checkins.map(c=>String(c.checked_in_at).slice(0,10)));$('#client-checkin-list').innerHTML=checkins.length?checkins.slice(0,30).map(c=>`<div class="checkin-list-item"><div><div class="activity-title">${Trainw.escapeHTML(fmtDate(c.checked_in_at))}</div><div class="activity-meta">${Trainw.escapeHTML(String(c.method||'manual'))}</div></div><div class="client-pill">OK</div></div>`).join(''):`<p class="empty-state">${t('noData')}</p>`;$('#client-checkin-heatmap').innerHTML=Array.from({length:35},(_,i)=>{const dte=Trainw.addDays(new Date(),-(34-i)),key=Trainw.dateOnly(dte);const cls=['heatmap-cell',seen.has(key)?'hit':'',key===today?'today':''].filter(Boolean).join(' ');return `<div class="${cls}" title="${Trainw.escapeHTML(key)}"></div>`}).join('')}
function renderMessages(){const badge=$('#client-msg-badge'),unread=threads.reduce((n,tg)=>n+tg.messages.filter(m=>m.receiver_id===currentUserId&&!m.is_read).length,0);badge.textContent=String(unread);badge.classList.toggle('hidden',!unread);$('#client-thread-list').innerHTML=threads.length?threads.map(th=>{const last=th.messages[th.messages.length-1];return `<div class="thread-item ${activeThreadId===th.id?'active':''}" data-thread="${th.id}"><div class="thread-item-name">${Trainw.escapeHTML(th.name)}</div><div class="thread-item-sub">${Trainw.escapeHTML(th.role)}</div><div class="thread-item-sub">${Trainw.escapeHTML(last?.content||'')}</div></div>`}).join(''):`<p class="empty-state">${t('noMessages')}</p>`;if(!activeThreadId&&threads[0])openThread(threads[0].id)}
async function openThread(id){activeThreadId=id;renderMessages();const th=threads.find(x=>x.id===id);if(!th)return;$('#client-conv-empty').classList.add('hidden');$('#client-conv-wrap').classList.remove('hidden');$('#client-conv-header').innerHTML=`<strong>${Trainw.escapeHTML(th.name)}</strong><div class="activity-meta">${Trainw.escapeHTML(th.role)}</div>`;$('#client-conv-messages').innerHTML=th.messages.length?th.messages.map(m=>`<div class="thread-message ${m.sender_id===currentUserId?'mine':''}"><div>${Trainw.escapeHTML(m.content||'')}</div><div class="thread-message-meta">${Trainw.escapeHTML(fmtDateTime(m.created_at))}</div></div>`).join(''):`<p class="empty-state">${t('noMessages')}</p>`;await Trainw.api.run(sb.from('messages').update({is_read:true}).eq('receiver_id',currentUserId).eq('sender_id',id),{context:'mark messages read',fallback:null})}
function renderProfileCoach(){if(coachInfo)$('#profile-coach-card').innerHTML=`<div class="profile-coach"><div class="profile-coach-avatar">${Trainw.escapeHTML(initials(coachInfo.name))}</div><div><div class="activity-title">${Trainw.escapeHTML(coachInfo.name)}</div><div class="activity-meta">${Trainw.escapeHTML(coachInfo.specialty||'')}</div></div></div>`;else $('#profile-coach-card').innerHTML=`<p class="empty-state">${t('noData')}</p>`}
function renderAll(){applyTranslations();$('#sidebar-client-name').textContent=safe(currentProfile?.name||currentProfile?.email||'Client');$('#profile-name').value=currentProfile?.name||'';$('#profile-phone').value=currentProfile?.phone||'';$('#profile-email').value=currentProfile?.email||'';$('#profile-membership').value=(clientProfile?.membership_tier||'basic').toUpperCase();renderDashboard();renderProgram();renderWeight();renderGoals();renderCheckins();renderMessages();renderProfileCoach();lucide.createIcons()}
function setReviewDraft(sessionId,patch){const current=reviewDrafts.get(sessionId)||{rating:0,comment:''};reviewDrafts.set(sessionId,{...current,...patch})}
async function bookSelectedSession(){if(!selectedBookingCoachId||!selectedBookingDate||!selectedBookingSlot){Trainw.ui.showToast(t('bookingNeedsSelection'),'info');return}const notes=$('#booking-notes-input')?.value.trim()||null;const r=await Trainw.api.run(sb.rpc('book_coach_session',{p_coach_id:selectedBookingCoachId,p_session_date:selectedBookingDate,p_start_time:selectedBookingSlot,p_notes:notes}),{context:'book coach session',fallback:null});if(r.error)return;selectedBookingSlot='';$('#booking-notes-input').value='';Trainw.ui.showToast(t('bookingSaved'),'success');await loadData()}
async function cancelSession(sessionId){const r=await Trainw.api.run(sb.rpc('cancel_session_booking',{p_session_id:sessionId,p_reason:null}),{context:'cancel coach session',fallback:null});if(r.error)return;await loadData()}
async function submitSessionReview(sessionId){const textarea=$(`[data-review-comment="${sessionId}"]`);if(textarea)setReviewDraft(sessionId,{comment:textarea.value});const draft=reviewDrafts.get(sessionId)||{rating:0,comment:''};if(!draft.rating){Trainw.ui.showToast(t('reviewRatingLabel'),'info');return}const r=await Trainw.api.run(sb.rpc('leave_session_review',{p_session_id:sessionId,p_rating:draft.rating,p_comment:draft.comment?.trim()||null}),{context:'leave session review',fallback:null});if(r.error)return;reviewDrafts.delete(sessionId);Trainw.ui.showToast(t('reviewSaved'),'success');await loadData()}
async function saveWeight(){const r=await Trainw.api.run(sb.from('weight_logs').insert({client_id:currentUserId,gym_id:currentGymId,logged_by:currentUserId,weight_kg:+($('#weight-input').value||0),body_fat_pct:$('#bodyfat-input').value?+$('#bodyfat-input').value:null,notes:$('#weight-notes-input').value||null,logged_at:($('#weight-date-input').value||Trainw.dateOnly(new Date()))+'T12:00:00'}),{context:'save weight',fallback:null});if(r.error)return;Trainw.ui.showToast(t('weightSaved'),'success');await loadData()}
async function saveGoal(){const payload={client_id:currentUserId,gym_id:currentGymId,goal_type:$('#goal-type-input').value,target_weight_kg:$('#goal-target-weight').value?+$('#goal-target-weight').value:null,target_date:$('#goal-date-input').value||null,notes:$('#goal-notes-input').value||null};const r=currentGoal?.id?await Trainw.api.run(sb.from('client_goals').update(payload).eq('id',currentGoal.id),{context:'update goal',fallback:null}):await Trainw.api.run(sb.from('client_goals').insert(payload),{context:'insert goal',fallback:null});if(r.error)return;Trainw.ui.showToast(t('goalSaved'),'success');await loadData()}
async function submitCheckin(){const today=Trainw.dateOnly(new Date());if(checkins.some(c=>String(c.checked_in_at).slice(0,10)===today)){Trainw.ui.showToast(t('checkinAlready'),'info');return}const r=await Trainw.api.run(sb.from('check_ins').insert({client_id:currentUserId,gym_id:currentGymId,method:'manual'}),{context:'client checkin',fallback:null});if(r.error)return;$('#client-checkin-feedback').textContent=t('checkinDone');$('#btn-client-checkin').classList.add('pulse-success');setTimeout(()=>$('#btn-client-checkin').classList.remove('pulse-success'),600);await loadData()}
async function saveProfile(){const r=await Trainw.api.run(sb.from('users').update({name:$('#profile-name').value.trim()||null,phone:$('#profile-phone').value.trim()||null,language_preference:currentLang}).eq('id',currentUserId),{context:'save client profile',fallback:null});if(r.error)return;Trainw.ui.showToast(t('profileSaved'),'success');currentProfile.name=$('#profile-name').value.trim()||'';currentProfile.phone=$('#profile-phone').value.trim()||'';renderAll()}
async function sendClientMessage(){const thread=threads.find(x=>x.id===activeThreadId),content=$('#client-msg-input').value.trim();if(!thread||!content)return;const r=await Trainw.api.run(sb.from('messages').insert({sender_id:currentUserId,receiver_id:thread.id,gym_id:currentGymId,content}),{context:'send client message',fallback:null});if(r.error)return;$('#client-msg-input').value='';Trainw.ui.showToast(t('messageSent'),'success');await loadData();openThread(thread.id)}
function todayWorkoutSets(){const todays=planExercises.filter(x=>weekdayMatch(x.day_label));const flat=[];todays.forEach(ex=>{const total=Number(ex.sets||0);for(let i=1;i<=total;i+=1)flat.push({exercise:ex,setNumber:i,totalSets:total})});return flat}
function beep(){try{const a=new(window.AudioContext||window.webkitAudioContext)(),o=a.createOscillator(),g=a.createGain();o.connect(g);g.connect(a.destination);o.type='sine';o.frequency.value=880;g.gain.value=.06;o.start();o.stop(a.currentTime+.12)}catch(e){}}
function startWorkout(){const sets=todayWorkoutSets();if(!sets.length){Trainw.ui.showToast(t('noWorkoutToday'),'info');return}activeWorkout={startedAt:Date.now(),sets,index:0,results:[],restTimer:null};$('#active-workout-backdrop').classList.remove('hidden');$('#active-workout-overlay').classList.remove('hidden');$('#workout-summary').classList.add('hidden');renderWorkoutStep()}
function currentSet(){return activeWorkout?.sets?.[activeWorkout.index]||null}
function renderWorkoutStep(){const step=currentSet();if(!step){const mins=Math.max(1,Math.round((Date.now()-activeWorkout.startedAt)/60000));$('#workout-step-copy').textContent=t('workoutSummary');$('#workout-exercise-name').textContent=t('workoutSummary');$('#workout-exercise-target').textContent=`${activeWorkout.results.length} sets · ${mins} min`;$('#workout-rest-timer').textContent='';$('#workout-summary').classList.remove('hidden');$('#workout-summary-copy').textContent=activeWorkout.results.map(r=>r.exercise_name+' '+r.reps_done+'x'+r.weight_kg).join(' · ');return}$('#workout-summary').classList.add('hidden');$('#workout-step-copy').textContent=`${activeWorkout.index+1}/${activeWorkout.sets.length}`;$('#workout-exercise-name').textContent=step.exercise.exercise_name;$('#workout-exercise-target').textContent=`Set ${step.setNumber}/${step.totalSets} · ${safe(step.exercise.reps)} reps · ${safe(step.exercise.rest_seconds,0)}s rest`;$('#workout-rest-timer').textContent=String(safe(step.exercise.rest_seconds,0));$('#workout-reps-input').value='';$('#workout-weight-input').value=''}
function runRest(sec){clearInterval(activeWorkout.restTimer);let left=sec||0;$('#workout-rest-timer').textContent=String(left);activeWorkout.restTimer=setInterval(()=>{left=Math.max(0,left-1);$('#workout-rest-timer').textContent=String(left);if(left<=3&&left>0)beep();if(left===0)clearInterval(activeWorkout.restTimer)},1000)}
function completeSet(){const step=currentSet();if(!step)return;activeWorkout.results.push({exercise_name:step.exercise.exercise_name,set_number:step.setNumber,reps_done:+($('#workout-reps-input').value||step.exercise.reps||0),weight_kg:+($('#workout-weight-input').value||0),notes:null});activeWorkout.index+=1;if(currentSet())runRest(Number(step.exercise.rest_seconds||0));renderWorkoutStep()}
async function finishWorkout(){const mins=Math.max(1,Math.round((Date.now()-activeWorkout.startedAt)/60000));const logRes=await Trainw.api.run(sb.from('workout_logs').insert({client_id:currentUserId,gym_id:currentGymId,plan_id:activePlan?.id||null,logged_by:currentUserId,duration_minutes:mins,notes:$('#workout-notes-input').value||null,perceived_effort:+($('#workout-effort-input').value||6)}).select('id').maybeSingle(),{context:'save workout log',fallback:null});if(logRes.error||!logRes.data?.id)return;const setRes=await Trainw.api.run(sb.from('workout_log_sets').insert(activeWorkout.results.map(r=>({...r,log_id:logRes.data.id}))),{context:'save workout sets',fallback:null});if(setRes.error)return;Trainw.ui.showToast(t('workoutSaved'),'success');closeWorkout();await loadData()}
function closeWorkout(){clearInterval(activeWorkout?.restTimer);activeWorkout=null;$('#active-workout-backdrop').classList.add('hidden');$('#active-workout-overlay').classList.add('hidden')}
function randomGateTokenSegment(){return Math.random().toString(36).slice(2,10)}
function clearGateCountdownTimer(){if(gateQrCountdownTimer){clearInterval(gateQrCountdownTimer);gateQrCountdownTimer=null}}
function updateGateCountdownLabel(){const el=$('#gate-qr-countdown'),c=$('#gate-qr-container');if(!el||!c)return;const key=c.dataset.emptyKey;if(key==='gateAccessNoGym')return el.textContent=t('gateAccessNoGym');if(key==='gateAccessError')return el.textContent=t('gateAccessUnavailable');if(key==='gateAccessLoading')return el.textContent=t('gateAccessLoading');if(!gateQrToken)return el.textContent=t('gateAccessUnavailable');el.textContent=t('gateAccessRefresh').replace('{seconds}',String(gateQrCountdownValue))}
function renderGateQrPlaceholder(key){const c=$('#gate-qr-container');if(!c)return;c.dataset.emptyKey=key;c.innerHTML=`<div class="gate-qr-empty">${Trainw.escapeHTML(t(key))}</div>`;gateQrToken='';updateGateCountdownLabel()}
function renderGateQr(token){const c=$('#gate-qr-container');if(!c||typeof QRCode==='undefined')return;c.dataset.emptyKey='';c.innerHTML='';new QRCode(c,{text:token,width:180,height:180,colorDark:'#000000',colorLight:'#ffffff',correctLevel:QRCode.CorrectLevel.M});gateQrToken=token;updateGateCountdownLabel()}
function startGateCountdown(){clearGateCountdownTimer();gateQrCountdownValue=55;updateGateCountdownLabel();gateQrCountdownTimer=setInterval(()=>{gateQrCountdownValue=Math.max(0,gateQrCountdownValue-1);updateGateCountdownLabel();if(gateQrCountdownValue<=0)clearGateCountdownTimer()},1000)}
async function refreshGateQR(){if(!currentGymId)return renderGateQrPlaceholder('gateAccessNoGym');renderGateQrPlaceholder('gateAccessLoading');const token=`${currentUserId}.${currentGymId}.${Date.now()}.${randomGateTokenSegment()}`;const r=await Trainw.api.run(sb.from('gate_sessions').insert({client_id:currentUserId,gym_id:currentGymId,token,expires_at:new Date(Date.now()+60000).toISOString(),used:false}),{context:'create gate session',fallback:null});if(r.error)return renderGateQrPlaceholder('gateAccessError');renderGateQr(token);startGateCountdown()}
async function initGateQR(){if(gateQrInitialized)return;gateQrInitialized=true;await refreshGateQR();gateQrRefreshTimer=setInterval(()=>refreshGateQR(),55000)}
async function bootstrap(){const ctx=await Trainw.auth.getContext(sb,{expectedRoles:['client'],loginHref:LOGIN_HREF});if(!ctx.session||!ctx.profile)return;currentProfile=ctx.profile;currentUserId=ctx.session.user.id;currentGymId=ctx.profile.gym_id||null;currentLang=localStorage.getItem('trainw_lang')||ctx.profile.language_preference||currentLang;applyTranslations();await loadData();await initGateQR();if(!window.__clientAuthBound){window.__clientAuthBound=true;Trainw.auth.watchAuth(sb,{onSignedOut:()=>window.location.href=LOGIN_HREF})}}
$$('.nav-item').forEach(n=>n.addEventListener('click',()=>showPage(n.dataset.page)));$$('.lang-btn').forEach(b=>b.addEventListener('click',()=>{currentLang=b.dataset.lang;localStorage.setItem('trainw_lang',currentLang);renderAll();updateGateCountdownLabel()}));$('#booking-coach-search').addEventListener('input',renderBookingComposer);$('#booking-date-input').addEventListener('change',async e=>{selectedBookingDate=e.target.value;selectedBookingSlot='';await loadBookingSlots();renderBookingComposer()});$('#booking-coach-list').addEventListener('click',async e=>{const card=e.target.closest('[data-book-coach]');if(!card)return;selectedBookingCoachId=card.dataset.bookCoach;selectedBookingSlot='';await loadBookingSlots();renderBookingComposer()});$('#booking-slot-list').addEventListener('click',e=>{const slot=e.target.closest('[data-slot-time]');if(!slot)return;selectedBookingSlot=slot.dataset.slotTime;renderBookingComposer()});$('#btn-book-session').addEventListener('click',bookSelectedSession);$('#dashboard-upcoming-list').addEventListener('click',e=>{const cancel=e.target.closest('[data-cancel-session]');if(cancel)cancelSession(cancel.dataset.cancelSession)});$('#client-past-sessions-list').addEventListener('click',e=>{const star=e.target.closest('[data-review-rating]');if(star){setReviewDraft(star.dataset.reviewSession,{rating:+star.dataset.reviewRating||0});renderPastSessions();return}const submit=e.target.closest('[data-review-submit]');if(submit)submitSessionReview(submit.dataset.reviewSubmit)});$('#client-past-sessions-list').addEventListener('input',e=>{const area=e.target.closest('[data-review-comment]');if(area)setReviewDraft(area.dataset.reviewComment,{comment:area.value})});$('#btn-save-weight').addEventListener('click',saveWeight);$('#toggle-bodyfat').addEventListener('change',renderWeight);$('#btn-save-goal').addEventListener('click',saveGoal);$('#btn-client-checkin').addEventListener('click',submitCheckin);$('#btn-save-profile').addEventListener('click',saveProfile);$('#btn-reset-password').addEventListener('click',async()=>{await sb.auth.resetPasswordForEmail(currentProfile.email);Trainw.ui.showToast(t('passwordResetSent'),'success')});$('#btn-send-client-message').addEventListener('click',sendClientMessage);$('#client-msg-input').addEventListener('keydown',e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();sendClientMessage()}});$('#client-thread-list').addEventListener('click',e=>{const thread=e.target.closest('[data-thread]');if(thread)openThread(thread.dataset.thread)});$('#program-accordion').addEventListener('click',e=>{const toggle=e.target.closest('[data-toggle-day]');if(toggle)toggle.closest('.program-day-card')?.classList.toggle('open')});$('#btn-start-workout').addEventListener('click',startWorkout);$('#btn-close-workout').addEventListener('click',closeWorkout);$('#btn-complete-set').addEventListener('click',completeSet);$('#btn-finish-workout').addEventListener('click',finishWorkout);$('#btn-logout').addEventListener('click',async()=>{await sb.auth.signOut();window.location.href=LOGIN_HREF});bootstrap();
